export function getPageForSection(section) {
  // Exact match
  if (SECTION_PAGES[section]) return SECTION_PAGES[section]
  // Try parent (e.g. 18.2.1 -> 18.2 -> 18.0)
  const parts = section.split('.')
  while (parts.length > 1) {
    parts.pop()
    const parent = parts.join('.')
    if (SECTION_PAGES[parent]) return SECTION_PAGES[parent]
  }
  return 1
}
